        return if(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._channels)) && channel < this._channels!!.channelList.length))  ((this._channels!!.channelList[(channel).toInt()].bank).toInt() and 32767).toDouble() else 0.0
    }
    
