    /**
     * Loads the presets from the given SoundFont hydra structure.
     */
    public override fun loadPresets(hydra: com.omnifret.gplayer.synth.soundfont.Hydra, instrumentPrograms: com.omnifret.gplayer.core.ecmaScript.Set<Double>, percussionKeys: com.omnifret.gplayer.core.ecmaScript.Set<Double>, append: Boolean): Unit{
        var newPresets: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.synthesis.Preset> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.synthesis.Preset>(
        )
        
        if (true) {
            var phdrIndex: Double = 0.0
            
            while(phdrIndex < hydra.phdrs.length - (1.0).toDouble()){
                var phdr: com.omnifret.gplayer.synth.soundfont.HydraPhdr = hydra.phdrs[(phdrIndex).toInt()]
                var regionIndex: Double = 0.0
                var preset: com.omnifret.gplayer.synth.synthesis.Preset = com.omnifret.gplayer.synth.synthesis.Preset()
                newPresets.push(preset)
                preset.name = phdr.presetName
                preset.bank = phdr.bank
                preset.presetNumber = phdr.preset
                var regionNum: Double = 0.0
                if (true) {
                    var pbagIndex: Double = phdr.presetBagNdx
                    
                    while(pbagIndex < hydra.phdrs[(phdrIndex + 1.0).toInt()].presetBagNdx){
                        var pbag: com.omnifret.gplayer.synth.soundfont.HydraPbag = hydra.pbags[(pbagIndex).toInt()]
                        var plokey: Double = 0.0
                        var phikey: Double = 127.0
                        var plovel: Double = 0.0
                        var phivel: Double = 127.0
                        if (true) {
                            var pgenIndex: Double = pbag.genNdx
                            
                            while(pgenIndex < hydra.pbags[(pbagIndex + 1.0).toInt()].genNdx){
                                var pgen: com.omnifret.gplayer.synth.soundfont.HydraPgen = hydra.pgens[(pgenIndex).toInt()]
                                if (pgen.genOper == com.omnifret.gplayer.synth.soundfont.HydraPgen.GenKeyRange)
                                {
                                    plokey = pgen.genAmount.lowByteAmount
                                    phikey = pgen.genAmount.highByteAmount
                                    pgenIndex++
                                    continue
                                }
                                if (pgen.genOper == com.omnifret.gplayer.synth.soundfont.HydraPgen.GenVelRange)
                                {
                                    plovel = pgen.genAmount.lowByteAmount
                                    phivel = pgen.genAmount.highByteAmount
                                    pgenIndex++
                                    continue
                                }
                                if (pgen.genOper != com.omnifret.gplayer.synth.soundfont.HydraPgen.GenInstrument)
                                {
                                    pgenIndex++
                                    continue
                                }
                                if (pgen.genAmount.wordAmount >= hydra.insts.length)
                                {
                                    pgenIndex++
                                    continue
                                }
                                var pinst: com.omnifret.gplayer.synth.soundfont.HydraInst = hydra.insts[(pgen.genAmount.wordAmount).toInt()]
                                if (true) {
                                    var ibagIndex: Double = pinst.instBagNdx
                                    
                                    while(ibagIndex < hydra.insts[(pgen.genAmount.wordAmount + 1.0).toInt()].instBagNdx){
                                        var ibag: com.omnifret.gplayer.synth.soundfont.HydraIbag = hydra.ibags[(ibagIndex).toInt()]
                                        var ilokey: Double = 0.0
                                        var ihikey: Double = 127.0
                                        var ilovel: Double = 0.0
                                        var ihivel: Double = 127.0
                                        if (true) {
                                            var igenIndex: Double = ibag.instGenNdx
                                            
                                            while(igenIndex < hydra.ibags[(ibagIndex + 1.0).toInt()].instGenNdx){
                                                var igen: com.omnifret.gplayer.synth.soundfont.HydraIgen = hydra.igens[(igenIndex).toInt()]
                                                if (igen.genOper == com.omnifret.gplayer.synth.soundfont.HydraPgen.GenKeyRange)
                                                {
                                                    ilokey = igen.genAmount.lowByteAmount
                                                    ihikey = igen.genAmount.highByteAmount
                                                    igenIndex++
                                                    continue
                                                }
                                                if (igen.genOper == com.omnifret.gplayer.synth.soundfont.HydraPgen.GenVelRange)
                                                {
                                                    ilovel = igen.genAmount.lowByteAmount
                                                    ihivel = igen.genAmount.highByteAmount
                                                    igenIndex++
                                                    continue
                                                }
                                                if (igen.genOper == 53.0 && ihikey >= plokey && ilokey <= phikey && ihivel >= plovel && ilovel <= phivel)
                                                {
                                                    regionNum++
                                                }
                                                igenIndex++
                                            }
                                        }
                                        ibagIndex++
                                    }
                                }
                                pgenIndex++
                            }
                        }
                        pbagIndex++
                    }
                }
                preset.regions = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.synthesis.Region>((regionNum).toInt())
                var globalRegion: com.omnifret.gplayer.synth.synthesis.Region = com.omnifret.gplayer.synth.synthesis.Region()
                globalRegion.clear(true)
                if (true) {
                    var pbagIndex: Double = phdr.presetBagNdx
                    
                    while(pbagIndex < hydra.phdrs[(phdrIndex + 1.0).toInt()].presetBagNdx){
                        var pbag: com.omnifret.gplayer.synth.soundfont.HydraPbag = hydra.pbags[(pbagIndex).toInt()]
                        var presetRegion: com.omnifret.gplayer.synth.synthesis.Region = com.omnifret.gplayer.synth.synthesis.Region(globalRegion)
                        var hadGenInstrument: Boolean = false
                        if (true) {
                            var pgenIndex: Double = pbag.genNdx
                            
                            while(pgenIndex < hydra.pbags[(pbagIndex + 1.0).toInt()].genNdx){
                                var pgen: com.omnifret.gplayer.synth.soundfont.HydraPgen = hydra.pgens[(pgenIndex).toInt()]
                                if (pgen.genOper == com.omnifret.gplayer.synth.soundfont.HydraPgen.GenInstrument)
                                {
                                    var whichInst: Double = pgen.genAmount.wordAmount
                                    if (whichInst >= hydra.insts.length)
                                    {
                                        pgenIndex++
                                        continue
                                    }
                                    var instRegion: com.omnifret.gplayer.synth.synthesis.Region = com.omnifret.gplayer.synth.synthesis.Region()
                                    instRegion.clear(false)
                                    var inst: com.omnifret.gplayer.synth.soundfont.HydraInst = hydra.insts[(whichInst).toInt()]
                                    if (true) {
                                        var ibagIndex: Double = inst.instBagNdx
                                        
                                        while(ibagIndex < hydra.insts[(whichInst + 1.0).toInt()].instBagNdx){
                                            var ibag: com.omnifret.gplayer.synth.soundfont.HydraIbag = hydra.ibags[(ibagIndex).toInt()]
                                            var zoneRegion: com.omnifret.gplayer.synth.synthesis.Region = com.omnifret.gplayer.synth.synthesis.Region(instRegion)
                                            var hadSampleId: Boolean = false
                                            if (true) {
                                                var igenIndex: Double = ibag.instGenNdx
                                                
                                                while(igenIndex < hydra.ibags[(ibagIndex + 1.0).toInt()].instGenNdx){
                                                    var igen: com.omnifret.gplayer.synth.soundfont.HydraIgen = hydra.igens[(igenIndex).toInt()]
                                                    if (igen.genOper == com.omnifret.gplayer.synth.soundfont.HydraPgen.GenSampleId)
                                                    {
                                                        if (zoneRegion.hiKey < presetRegion.loKey || zoneRegion.loKey > presetRegion.hiKey)
                                                        {
                                                            igenIndex++
                                                            continue
                                                        }
                                                        if (zoneRegion.hiVel < presetRegion.loVel || zoneRegion.loVel > presetRegion.hiVel)
                                                        {
                                                            igenIndex++
                                                            continue
                                                        }
                                                        if (presetRegion.loKey > zoneRegion.loKey)
                                                        {
                                                            zoneRegion.loKey = presetRegion.loKey
                                                        }
                                                        if (presetRegion.hiKey < zoneRegion.hiKey)
                                                        {
                                                            zoneRegion.hiKey = presetRegion.hiKey
                                                        }
                                                        if (presetRegion.loVel > zoneRegion.loVel)
                                                        {
                                                            zoneRegion.loVel = presetRegion.loVel
                                                        }
                                                        if (presetRegion.hiVel < zoneRegion.hiVel)
                                                        {
                                                            zoneRegion.hiVel = presetRegion.hiVel
                                                        }
                                                        zoneRegion.offset += presetRegion.offset
                                                        zoneRegion.end += presetRegion.end
                                                        zoneRegion.loopStart += presetRegion.loopStart
                                                        zoneRegion.loopEnd += presetRegion.loopEnd
                                                        zoneRegion.transpose += presetRegion.transpose
                                                        zoneRegion.tune += presetRegion.tune
                                                        zoneRegion.pitchKeyTrack += presetRegion.pitchKeyTrack
                                                        zoneRegion.attenuation += presetRegion.attenuation
                                                        zoneRegion.pan += presetRegion.pan
                                                        zoneRegion.ampEnv.delay += presetRegion.ampEnv.delay
                                                        zoneRegion.ampEnv.attack += presetRegion.ampEnv.attack
                                                        zoneRegion.ampEnv.hold += presetRegion.ampEnv.hold
                                                        zoneRegion.ampEnv.decay += presetRegion.ampEnv.decay
                                                        zoneRegion.ampEnv.sustain += presetRegion.ampEnv.sustain
                                                        zoneRegion.ampEnv.release += presetRegion.ampEnv.release
                                                        zoneRegion.modEnv.delay += presetRegion.modEnv.delay
                                                        zoneRegion.modEnv.attack += presetRegion.modEnv.attack
                                                        zoneRegion.modEnv.hold += presetRegion.modEnv.hold
                                                        zoneRegion.modEnv.decay += presetRegion.modEnv.decay
                                                        zoneRegion.modEnv.sustain += presetRegion.modEnv.sustain
                                                        zoneRegion.modEnv.release += presetRegion.modEnv.release
                                                        zoneRegion.initialFilterQ += presetRegion.initialFilterQ
                                                        zoneRegion.initialFilterFc += presetRegion.initialFilterFc
                                                        zoneRegion.modEnvToPitch += presetRegion.modEnvToPitch
                                                        zoneRegion.modEnvToFilterFc += presetRegion.modEnvToFilterFc
                                                        zoneRegion.delayModLFO += presetRegion.delayModLFO
                                                        zoneRegion.freqModLFO += presetRegion.freqModLFO
                                                        zoneRegion.modLfoToPitch += presetRegion.modLfoToPitch
                                                        zoneRegion.modLfoToFilterFc += presetRegion.modLfoToFilterFc
                                                        zoneRegion.modLfoToVolume += presetRegion.modLfoToVolume
                                                        zoneRegion.delayVibLFO += presetRegion.delayVibLFO
                                                        zoneRegion.freqVibLFO += presetRegion.freqVibLFO
                                                        zoneRegion.vibLfoToPitch += presetRegion.vibLfoToPitch
                                                        zoneRegion.ampEnv.envToSecs(true)
                                                        zoneRegion.modEnv.envToSecs(false)
                                                        zoneRegion.delayModLFO = if(zoneRegion.delayModLFO < -11950.0)  0.0 else com.omnifret.gplayer.synth.SynthHelper.timecents2Secs(zoneRegion.delayModLFO)
                                                        zoneRegion.delayVibLFO = if(zoneRegion.delayVibLFO < -11950.0)  0.0 else com.omnifret.gplayer.synth.SynthHelper.timecents2Secs(zoneRegion.delayVibLFO)
                                                        if (zoneRegion.pan < -0.5)
                                                        {
                                                            zoneRegion.pan = -0.5
                                                        }
                                                        else if (zoneRegion.pan > 0.5)
                                                        {
                                                            zoneRegion.pan = 0.5
                                                        }
                                                        if (zoneRegion.initialFilterQ < 1500 || zoneRegion.initialFilterQ > 13500)
                                                        {
                                                            zoneRegion.initialFilterQ = 0.0
                                                        }
                                                        var shdr: com.omnifret.gplayer.synth.soundfont.HydraShdr = hydra.sHdrs[(igen.genAmount.wordAmount).toInt()]
                                                        zoneRegion.offset += shdr.start
                                                        zoneRegion.end += shdr.end
                                                        zoneRegion.loopStart += shdr.startLoop
                                                        zoneRegion.loopEnd += shdr.endLoop
                                                        if (shdr.endLoop > 0)
                                                        {
                                                            zoneRegion.loopEnd -= 1.0
                                                        }
                                                        if (zoneRegion.pitchKeyCenter == -1.0)
                                                        {
                                                            zoneRegion.pitchKeyCenter = shdr.originalPitch
                                                        }
                                                        zoneRegion.tune += shdr.pitchCorrection
                                                        zoneRegion.sampleRate = shdr.sampleRate
                                                        var isPercussion: Boolean = phdr.bank == com.omnifret.gplayer.synth.SynthConstants.PercussionBank
                                                        var shouldLoadSamples: Boolean = (isPercussion && com.omnifret.gplayer.synth.synthesis.TinySoundFont._setContainsRange(percussionKeys, zoneRegion.loKey, zoneRegion.hiKey)) || (!isPercussion && instrumentPrograms.has(phdr.preset))
                                                        if (!shouldLoadSamples)
                                                        {
                                                            com.omnifret.gplayer.Logger.debug("GPlayerSynth", """Skipping load of unused sample ${(shdr.sampleName).toTemplate()} for preset ${(phdr.presetName).toTemplate()} (bank ${(preset.bank).toTemplate()} program ${(preset.presetNumber).toTemplate()})""")
                                                            zoneRegion.samples = com.omnifret.gplayer.core.ecmaScript.Float32Array(0.0)
                                                        }
                                                        else if (((shdr.sampleType).toInt() and 1) != 0)
                                                        {
                                                            com.omnifret.gplayer.Logger.debug("GPlayerSynth", """Loading of used sample ${(shdr.sampleName).toTemplate()} for preset ${(phdr.presetName).toTemplate()} (bank ${(preset.bank).toTemplate()} program ${(preset.presetNumber).toTemplate()})""")
                                                            var decompressVorbis: Boolean = ((shdr.sampleType).toInt() and 16) != 0
                                                            if (decompressVorbis)
                                                            {
                                                                zoneRegion.samples = hydra.decodeSamples(shdr.start, shdr.end, true)
                                                            }
                                                            else 
                                                            {
                                                                zoneRegion.samples = hydra.decodeSamples(zoneRegion.offset * (2.0).toDouble(), zoneRegion.end * (2.0).toDouble(), false)
                                                                if (zoneRegion.loopStart > 0)
                                                                {
                                                                    zoneRegion.loopStart -= zoneRegion.offset
                                                                }
                                                                if (zoneRegion.loopEnd > 0)
                                                                {
                                                                    zoneRegion.loopEnd -= zoneRegion.offset
                                                                }
                                                            }
                                                            zoneRegion.offset = 0.0
                                                            zoneRegion.end = zoneRegion.samples.length - (1.0).toDouble()
                                                        }
                                                        else 
                                                        {
                                                            com.omnifret.gplayer.Logger.warning("GPlayerSynth", """Skipping load of unsupported sample ${(shdr.sampleName).toTemplate()} for preset ${(phdr.presetName).toTemplate()}, sample type ${(shdr.sampleType).toTemplate()} is not supported (bank ${(preset.bank).toTemplate()} program ${(preset.presetNumber).toTemplate()})""")
                                                            zoneRegion.samples = com.omnifret.gplayer.core.ecmaScript.Float32Array(0.0)
                                                        }
                                                        preset.regions!![(regionIndex).toInt()] = com.omnifret.gplayer.synth.synthesis.Region(zoneRegion)
                                                        regionIndex++
                                                        hadSampleId = true
                                                    }
                                                    else 
                                                    {
                                                        zoneRegion.`operator`(igen.genOper, igen.genAmount)
                                                    }
                                                    igenIndex++
                                                }
                                            }
                                            if (ibag == hydra.ibags[(inst.instBagNdx).toInt()] && !hadSampleId)
                                            {
                                                instRegion = com.omnifret.gplayer.synth.synthesis.Region(zoneRegion)
                                            }
                                            ibagIndex++
                                        }
                                    }
                                    hadGenInstrument = true
                                }
                                else 
                                {
                                    presetRegion.`operator`(pgen.genOper, pgen.genAmount)
                                }
                                pgenIndex++
                            }
                        }
                        if (pbag == hydra.pbags[(phdr.presetBagNdx).toInt()] && !hadGenInstrument)
                        {
                            globalRegion = presetRegion
                        }
                        pbagIndex++
                    }
                }
                phdrIndex++
            }
        }
        if (!append || !com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.presets)))
        {
            this.presets = newPresets
        }
        else 
        {
            for (preset in newPresets)
            {
                this.presets!!.push(preset)
            }
        }
    }
    
    /**
     * Checks whether the synth has loaded the samples for a given midi program.
     */
    public override fun hasSamplesForProgram(program: Double): Boolean{
        var presets: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.synthesis.Preset>? = this.presets
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(presets)))
        {
            return false
        }
        for (preset in presets!!)
        {
            if (preset.presetNumber == program)
            {
                for (region in preset.regions!!)
                {
                    if (region.samples.length > 0)
                    {
                        return true
                    }
                }
            }
        }
        return false
    }
    
    /**
     * Checks whether the synth has loaded the samples for a given percussion key.
     */
    public override fun hasSamplesForPercussion(key: Double): Boolean{
        var presets: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.synthesis.Preset>? = this.presets
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(presets)))
        {
            return false
        }
        for (preset in presets!!)
        {
            if (preset.bank == com.omnifret.gplayer.synth.SynthConstants.PercussionBank)
            {
                for (region in preset.regions!!)
                {
                    if (region.loKey >= key && region.hiKey <= key && region.samples.length > 0)
                    {
                        return true
                    }
                }
            }
        }
        return false
    }
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _setContainsRange(x: com.omnifret.gplayer.core.ecmaScript.Set<Double>, lo: Double, hi: Double): Boolean{
            if (true) {
                var i: Double = lo
                
                while(i <= hi){
                    if (x.has(i))
                    {
                        return true
                    }
                    i++
                }
            }
            return false
        }
        
    }
